$_MODULE['<{opartdevis}prestashop>faq_1fe917b01f9a3f87fa2d7d3b7643fac1'] = 'FAQ';
$_MODULE['<{opartdevis}prestashop>faq_a4be6984c377fe11d8a50313ed0b6163'] = 'Comment limiter la possibilité de transformer un panier en devis à certains groupes de clients ?';
$_MODULE['<{opartdevis}prestashop>faq_d08042046897d46e889dfdd43f805942'] = ' Pour limiter l’utilisation du module de devis à un certains groupes de clients, vous devez vous rendre dans la rubrique “paramètres de Prestashop -> clients -> groupes “';
$_MODULE['<{opartdevis}prestashop>faq_81eb3506c5871f920c9c555fdcb5c6d2'] = ' Cliquez ensuite sur le groupe que vous souhaitez modifier.';
$_MODULE['<{opartdevis}prestashop>faq_b8b9897a243fd6274f757bdb8714d178'] = 'Pour chaque groupe de client, vous pouvez activer ou non les modules disponibles pour votre boutique.';
$_MODULE['<{opartdevis}prestashop>faq_0f7331852c7e452d4171455c8a4e1c37'] = 'De base, les modules activés sont disponibles pour tous les groupes de clients. Ainsi, si vous souhaitez limiter l’utilisation du module de devis à certains groupes de clients, vous devez modifier les groupes qui n’auront plus accès et désactiver le module pour ce groupe';
$_MODULE['<{opartdevis}prestashop>faq_158d10181e6aa7b90f114de6f709b086'] = 'Le module n’apparaît pas sur la page du compte client';
$_MODULE['<{opartdevis}prestashop>faq_7f7af2c26005a6ec38d2566882e360d9'] = 'Pour les thèmes classiques, il n’y a aucune opération à faire, le module est bien présent de base.';
$_MODULE['<{opartdevis}prestashop>faq_b3a7ea03bb43ac097833d7a3ba8bfe02'] = 'Si vous utilisez le thème WareHouse ';
$_MODULE['<{opartdevis}prestashop>faq_29c3ce7917dfc127554aaa97e88730aa'] = 'Selon la version de votre thème, il est possible que le module ne soit pas présent dans le menu disponible dans le compte client';
$_MODULE['<{opartdevis}prestashop>faq_1db3b074f66e527ba23338d9dda8900b'] = 'Si c’est le cas, il faut ajouter le point d’accroche dans le thème. Pour ce faire, vous devez modifier le fichier “page.tpl” en suivant ce chemin : themes/warehouse/templates/customer/page.tpl';
$_MODULE['<{opartdevis}prestashop>faq_ab5d64a2a866543de4d9173eae8f2378'] = 'Pour faire cet ajout, vous devez donc avoir accès à votre FTP.';
$_MODULE['<{opartdevis}prestashop>faq_f8c09d653182a9ec90ec12c16203e1a8'] = 'Dans le fichier “page.tpl”; vous devez ajouter cette ligne : ';
$_MODULE['<{opartdevis}prestashop>faq_947b0956b66488e0bab2a11dcad0b99d'] = 'Comment faire pour que le client ne puisse plus modifier le devis ?';
$_MODULE['<{opartdevis}prestashop>faq_1d8dbb9db536520377e98621c6c35ed4'] = 'Vos clients peuvent modifier les devis seulement s\'ils ne sont pas validés par votre part dans le back office.';
$_MODULE['<{opartdevis}prestashop>faq_159c6c34417ecc7c8b119f9d9b5917b5'] = 'Tant que le devis n\'est pas validé, le module considère que les clients peuvent encore modifier leur demande et donc apporter des modifications au devis';
$_MODULE['<{opartdevis}prestashop>faq_91264995bb0689fd83667d9e67f14901'] = 'Une fois validé par vos soins, le module considère qu\'il s\'agit de votre offre, ainsi la date de validité ne change plus et prend effet à partir du moment où vous le validé. La date, les prix ainsi que le contenu du devis ne sont alors plus modifiables.';
$_MODULE['<{opartdevis}prestashop>faq_f4e93a11722bcab1be8b7e62d98635d8'] = 'Comment modifier les frais de port manuellement sans tenir compte des règles de transport pré-enregistrées ?';
$_MODULE['<{opartdevis}prestashop>faq_5706be616ccfc10805ee59c73d20cf9f'] = 'Par défaut, le module utilise les transporteurs pré-enregistrés et ne permet pas d’ajouter les frais de port manuellement sur le devis.';
$_MODULE['<{opartdevis}prestashop>faq_5bdb477155797d69ee77e56680f5b67d'] = 'Cependant, si vous le désirez, nous pouvons faire un développement spécifique sur votre module pour qu’il autorise l’ajout de frais de port manuellement.';
$_MODULE['<{opartdevis}prestashop>faq_d64fd5de682d525ea33b204fc2c428dc'] = 'Contactez-nous pour en savoir plus. ';
